#include <iostream>
#include <stack>
#include <string>
using namespace std;

// Function to check if the string is palindrome using stack
bool is_palindrome(const string& s) {
    stack<char> stk;

    // Push all characters of the string onto the stack
    for (char ch : s) {
        stk.push(ch);
    }

    // Compare the characters in the string with the stack
    for (char ch : s) {
        if (ch != stk.top()) {
            return false;
        }
        stk.pop();
    }
    return true;
}

int main() {
    string s;

    // Input the string to check
    getline(cin, s);

    // Check if the string is a palindrome
    if (is_palindrome(s)) {
        cout << "Palindrome" << endl;
    } else {
        cout << "Not Palindrome" << endl;
    }

    return 0;
}

