#include <stdio.h>
#include <string.h>
#include <stdbool.h>

// Function to check if the string is palindrome using stack
bool is_palindrome(char* s) {
    int length = strlen(s);
    char stack[length];
    int top = -1;

    // Push all characters of the string onto the stack
    for (int i = 0; i < length; i++) {
        stack[++top] = s[i];
    }

    // Compare the characters in the string with the stack
    for (int i = 0; i < length; i++) {
        if (s[i] != stack[top--]) {
            return false;
        }
    }
    return true;
}

int main() {
    char s[1000];

    // Input the string to check
    fgets(s, sizeof(s), stdin);
    s[strcspn(s, "\n")] = 0;  // Remove newline character if present

    // Check if the string is a palindrome
    if (is_palindrome(s)) {
        printf("Palindrome\n");
    } else {
        printf("Not Palindrome\n");
    }

    return 0;
}

